import argparseimport os# project_pathfile_path = os.getcwd()project_path  = os.path.dirname(file_path)# print(project_path , "project_path")# dataset_pathdataset_path = os.path.join(project_path,"dataset")parser = argparse.ArgumentParser(description='Thermal and Rail SR')parser.add_argument('--debug', action='store_true',                    help='Enables debug mode')parser.add_argument('--template', default='.',                    help='You can set various templates in option.py')parser.add_argument('--project_path', type=str, default=project_path ,                    help='all dataset directory include train dataset and test dataset')# Hardware specificationsparser.add_argument('--n_threads', type=int, default=8,                    help='number of threads for data loading')parser.add_argument('--cpu', action='store_true',                    help='use cpu only')parser.add_argument('--n_GPUs', type=int, default=1,                    help='number of GPUs')parser.add_argument('--seed', type=int, default=1,                    help='random seed')# Data specificationsparser.add_argument('--dataset_path', type=str, default=dataset_path,                    help='all dataset directory include train dataset and test dataset')parser.add_argument('--data_train', type=str, default='DIV2K4xto2x',                    help='train dataset name')parser.add_argument('--data_test', type=str, default='DIV2K4xto2x',                    help='test dataset name')parser.add_argument('--num_class', type=int, default=2,                    help='image class numbeer ')parser.add_argument('--down_scale', type=int, default=1,                    help='input downsample scale ')parser.add_argument('--crop_traindata', type=str, default='False',                    help='the train data will be crop at the [h1:h2,w1:w1],the param of h1h2w1w2 you should set at data/dataset.py')parser.add_argument('--crop_testdata', type=str, default='False',                    help='the test data will be crop at the [h1:h2,w1:w1],the param of h1h2w1w2 you should set at data/dataset.py')parser.add_argument('--patch_size', type=int, default=128,                    help='control the input data crop patch (592,720), if patch_size != None it will be crop shuffle 作为正方形')parser.add_argument('--argument_scale', type=int, default=1,                    help='if the argunment scale is not 1 ,the train data will be argument  ')parser.add_argument('--rgb_range', type=int, default=1,                    help='the max range of input data ,if the rgb_range is 255 the data range will be 255 if the rgb_range is 1 ,the data will  be normliazation')parser.add_argument('--resize_traindata', type=int, default=None,                    help='control the input data resize ,if it is False input will not be resize else will be resize to the resolution ')parser.add_argument('--light_argument', type=int, default=1,                    help='if the light argunment is 1  ,the light of train data will be argument ')# Model specificationsparser.add_argument('--model', default='rcan',                    help='model name')parser.add_argument('--model2', default='None',                    help='model2 name is ususlly used for GAN and as the model_D ')# Training specificationsparser.add_argument('--reset', action='store_true',                    help='reset the training which have ')parser.add_argument('--test_every', type=int, default=1000,                    help='do test per every N batches')parser.add_argument('--epochs', type=int, default=300,                    help='number of epochs to train')parser.add_argument('--batch_size', type=int, default=8,                    help='input batch size for training')parser.add_argument('--test_only', action='store_true',                    help='set this option to test the model')# Optimization specificationsparser.add_argument('--optimizer', default='ADAM',                    choices=('SGD', 'ADAM', 'RMSprop'),                    help='optimizer to use (SGD | ADAM | RMSprop)')parser.add_argument('--lr', type=float, default=1e-4,                    help='learning rate')parser.add_argument('--lr2', type=float, default=1e-4,                    help='learning rate2 just for two model with two optimizer ')parser.add_argument('--decay', type=str, default='600-800',                    help='learning rate decay type')parser.add_argument('--gamma', type=float, default=0.8,                    help='learning rate decay factor for step decay')parser.add_argument('--momentum', type=float, default=0.9,                    help='SGD momentum')parser.add_argument('--betas', type=tuple, default=(0.9, 0.999),                    help='ADAM beta')parser.add_argument('--epsilon', type=float, default=1e-8,                    help='ADAM epsilon for numerical stability')parser.add_argument('--weight_decay', type=float, default=0,                    help='weight decay')parser.add_argument('--gclip', type=float, default=0,                    help='gradient clipping threshold (0 = no clipping)')# Loss specificationsparser.add_argument('--loss', type=str, default='1*L1',                    help='loss function configuration')parser.add_argument('--skip_threshold', type=float, default='1e8',                    help='skipping batch that has large error')parser.add_argument('--loss2', type=str, default='None',                    help='loss function configuration')# Log specificationsparser.add_argument('--resload_path', type=str, default='',                    help='file name to load ( load the pretrain model load) in experiment/train/ or test ')parser.add_argument('--ressave_path', type=str, default='TEST-EX1',                    help='file name to save ( will define the save_dir)  experiment/train/ressave_path or test')parser.add_argument('--resume', type=int, default= -2,                    help='resume from specific ckpoint')parser.add_argument('--pre_train', type=str, default='.',                    help='pre-trained model directory')parser.add_argument('--save_models', action='store_true',                    help='save all intermediate models')parser.add_argument('--save_models_every',type=int, default= 2,                    help='if save_models the number will control how much epoch model will save one time ')parser.add_argument('--print_every', type=int, default=100,                    help='how many batches to wait before logging training status')parser.add_argument('--save_results', action='store_true',                    help='save output results')parser.add_argument('--sw_mode', type=str, default='S',                    help='dasr mode control ')parser.add_argument('--scale', type=int, default=1,                    help='how many batches to wait before logging training status')parser.add_argument('--input_size', type=int, default=None,                    help='control the input data crop patch (592,720), if patch_size != None it will be crop shuffle 作为正方形')parser.add_argument('--test_idx', type=int, default=1,                    help='used by control in trainer_denoise_control to control the idx of test')# end the argsargs = parser.parse_args()# 这里将输入的data_train 就是用+号连接的分来为列表的形式args.data_train = args.data_train.split('+')args.data_test = args.data_test.split('+')if args.epochs == 0:    args.epochs = 1e8for arg in vars(args):    if vars(args)[arg] == 'True':        vars(args)[arg] = True    elif vars(args)[arg] == 'False':        vars(args)[arg] = Falseif __name__ == '__main__':    import os    path  = os.getcwd()    print(path)    path2 = os.path.dirname(os.getcwd()) # 获取路径的文件夹目录    print(path2,"path2")